#!/bin/bash

# This script is useful to create the memory profiling files for each model
# thanks to the .hef and the '_compiled.har' file generated by the hailo compiler during the compilation.
# The profiling is performed through the hailo compiler CLI tool. 


echo ""
echo "[INFO - PROFILING]"
echo ""
for file in ./hef_files/*.hef; do
    
    filename=$(echo $file | cut -d "." -f 2 | cut -d "/" -f 3)

     if [ -f ./memory_profiling_files/${filename}.csv ]; then
        echo "[INFO] FILE $filename ALREADY PROFILED!"
        continue
    fi

    har_file=./hef_files/${filename}_compiled.har

    if [ ! -f $har_file ]; then
        echo "[INFO] FILE ${har_file} NOT EXISTS. FALLBACK ON ./har_files_quantized/${filename}_quantized.har!"
        har_file=./har_files_quantized/${filename}_quantized.har
    fi


    echo ""
    echo "[INFO] PROFILING $file ..."

    hailo profiler $har_file --hef $file --csv ./memory_profiling_files/${filename}.csv
done
rm -f *.log ./hef_files/*.log ./hef_files/*.har estimation.csv *.html 
echo ""
